const jobResults = $input.item.json.jobs_results || [];
const params = $('Extract Search Parameters').first().json;
const profile = $('Load Skill Profile (Supabase)').first().json;

const negativeKeywords = [
  'mlm','commission only','door to door','crypto','adult','casino','gambling',
  'unpaid internship','volunteer only','equity only','no salary',
  'high ticket closer','life insurance only','cold calling'
];

const avoidIndustries = profile.avoid_industries || [];

const filtered = jobResults
  .filter(job => {
    const text = ((job.title || '') + ' ' + (job.company_name || '') + ' ' + (job.description || '')).toLowerCase();
    const blocked = [...negativeKeywords, ...avoidIndustries];
    return !blocked.some(kw => text.includes(kw.toLowerCase()));
  })
  .slice(0, 10)
  .map(job => ({
    company_name: job.company_name || 'Unknown',
    job_title: job.title || 'Unknown Role',
    job_url: job.share_link || job.job_apply_link || null,
    source: 'google_jobs',
    location: job.location || params.location,
    remote_status: params.remote_status,
    salary_range: job.detected_extensions?.salary || null,
    description: (job.description || '').slice(0, 1500),
    user_id: params.user_id,
    user_skills: profile.primary_skills || [],
    user_secondary_skills: profile.secondary_skills || [],
    user_tone: profile.tone || 'professional, helpful, direct',
    preferred_industries: profile.preferred_industries || []
  }));

return filtered.map(item => ({ json: item }));

const job = $('Filter & Normalize Jobs').item.json;
const claudeResponse = $input.item.json;

let analysis = {};
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  analysis = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  analysis = {
    fit_score: 50,
    pain_point_summary: 'Analysis unavailable',
    opportunity_type: 'job',
    opportunity_scores: { employment: 50, consulting: 30, agency: 20, automation: 20, saas: 10 },
    opportunity_classification: 'Green'
  };
}

return [{ json: { ...job, analysis } }];
